import os
import re
import subprocess
import urllib.request

def get_requirements(url):
    reqs = set()
    with urllib.request.urlopen(url) as response:
        lines = response.read().decode('utf-8').splitlines()
        for line in filter(bool, lines):
            match = re.search(r'^(\w+)=\w+$', line)
            if match:
                reqs.add(match.group(1))
    return list(reqs)

requirements_url = "https://example.com/path/to/your/requirements.txt"
install_requires = get_requirements(requirements_url)
extra_require = {'runtime': ['package-needed-at-runtime']}

from setuptools import setup, find_packages

setup(
    name='myproject',
    version='0.1',
    packages=find_packages(),
    install_requires=install_requires,
    extras_require={**extra_require},
    entry_points={},
)

# Execute additional pip commands for extra dependencies
additional_requirements = {'dev': ['package-needed-for-dev']}
for name, reqs in additional_requirements.items():
    print(f'Installing {name}...')
    subprocess.check_call([sys.executable, '-m', 'pip', 'install', *reqs])